const e="2026.1",i="2026-03-04";const t={heroTitle:"Secure your MCP deployment",heroSubtitle:"An open-source security checklist for the AI tool ecosystem. Track your progress across 228 controls derived from OWASP, SlowMist, and recent academic research.",ctaText:"Get started",siteTitle:"MCP Security Checklist",siteDescription:"An interactive, open-source security checklist for Model Context Protocol deployments, covering server security, client security, agentic workflows, governance, and more."},r=JSON.parse(`[{"id":"mcp-server","title":"MCP Server Security","icon":"Shield","description":"Server-side controls for MCP endpoints, tools, runtime isolation, and operational security.","number":1,"subsections":[{"id":"srv-api","number":"1.1","title":"API Security","items":[{"id":"srv-api-001","title":"Input Validation","description":"Enforce strict validation on all API inputs to prevent injection attacks, path traversal (../), and invalid parameters. Reject anything that doesn't match the defined JSON Schema.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-002","title":"Path Traversal Protection","description":"Validate all file path arguments against configured boundaries; prohibit directory traversal sequences. (82% of MCP servers fail this check per Endor Labs.)","priority":"CRITICAL","roles":["security-engineer"],"tags":["priority-critical","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-003","title":"Command Injection Prevention","description":"Sanitize all CLI flags and shell-bound parameters; never concatenate user input directly into system calls. (43% of MCP servers are vulnerable per Equixly.)","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-004","title":"API Rate Limiting","description":"Implement per-session and per-user call rate limits to prevent abuse and DoS attacks.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-005","title":"Output Encoding","description":"Properly encode all API outputs; prevent injection payloads from escaping serialization boundaries.","priority":"HIGH","roles":["developer"],"tags":["input-validation","prompt-injection","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-006","title":"Size Limits","description":"Enforce maximum size constraints on all inputs and outputs to prevent context overflows or memory exhaustion.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","runtime-security","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-007","title":"Schema-Driven Responses","description":"Define strict JSON schemas for all tool responses and reject deviations at the transport layer.","priority":"RECOMMENDED","roles":["architect","developer"],"tags":["input-validation","tool-security","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-api-901","title":"Recursive Validation and Unknown-Field Rejection","description":"Validate nested payload structures recursively and reject unknown fields by default to prevent parameter smuggling, schema pollution, and parser confusion attacks.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["input-validation","schema-validation","priority-critical"],"sources":[{"label":"Enterprise-Grade Security for MCP (arXiv:2504.08623v2)","url":"https://arxiv.org/abs/2504.08623v2"}]}],"description":"API endpoints are the primary interface between AI models and MCP servers. Weak validation here allows injection attacks, path traversal, and unauthorized access."},{"id":"srv-auth","number":"1.2","title":"Server Authentication & Authorization","items":[{"id":"srv-auth-001","title":"OAuth 2.1 / OIDC Enforcement","description":"All remote MCP servers must use OAuth 2.1 or OIDC for client and user identity. Validate iss, aud, exp, and signatures on every request.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-002","title":"No Token Passthrough","description":"Never forward client tokens to downstream APIs; use tokens explicitly issued to the MCP server or use validated OAuth \\"On-Behalf-Of\\" flows (RFC 8693). Direct passthrough creates a Confused Deputy vulnerability.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authentication","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-003","title":"Short-Lived, Scoped Tokens","description":"Issue access tokens with minimal lifetimes (minutes) and narrow scopes. Revalidate on each call before any tool or resource access.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authentication","authorization","tool-security","runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-004","title":"Least Privilege","description":"Run service processes and tools with the minimum required permissions. Never run as root.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","tool-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-005","title":"Role-Based Access Control (RBAC)","description":"Implement role-based access control, limiting resource access per identity and enforcing least privilege by default.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","authorization","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-006","title":"Credential Management","description":"Securely manage and store service credentials; never hard-code secrets; use secrets vaults (e.g., HashiCorp Vault, AWS Secrets Manager). Never expose secrets to the LLM layer.","priority":"HIGH","roles":["developer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-007","title":"External Service Authentication","description":"Use secure, scoped authentication when calling third-party services.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","authorization","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-008","title":"API Key Rotation","description":"Automatically rotate API keys and service credentials on a schedule; limit key validity windows.","priority":"HIGH","roles":["developer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-009","title":"Service Identity Authentication","description":"Provide a verifiable mechanism for clients to authenticate the server's identity.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-010","title":"Centralized Policy Enforcement","description":"Use a dedicated policy/gateway layer to enforce authentication, authorization, consent, tool filtering, and audit logging consistently across all agents and servers.","priority":"HIGH","roles":["compliance","devops","developer","security-engineer"],"tags":["authentication","tool-security","runtime-security","monitoring","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-011","title":"Dynamic Client Registration Protection","description":"If dynamic client registration is required, protect endpoints via access tokens, software statements (signed JWTs), or signed request bodies. Avoid open dynamic registration in production.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["authentication","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-012","title":"Session Treated as State, Not Identity","description":"Never rely on session IDs alone for authorization. Bind sessions to validated OAuth identity; rotate and expire aggressively.","priority":"RECOMMENDED","roles":["architect","security-engineer"],"tags":["authentication","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-auth-901","title":"Sender-Constrained Access Tokens","description":"Use sender-constrained tokens (DPoP or mTLS token binding) for MCP calls so stolen bearer tokens cannot be replayed from unauthorized clients.","priority":"HIGH","roles":["security-engineer","developer"],"tags":["authentication","zero-trust","token-security","priority-high"],"sources":[{"label":"Enterprise-Grade Security for MCP (arXiv:2504.08623v2)","url":"https://arxiv.org/abs/2504.08623v2"}]}],"description":"Authentication and authorization gate every request. Misconfigured identity controls create confused deputy vulnerabilities and unauthorized data access."},{"id":"srv-tool","number":"1.3","title":"Tool Security & Integrity","items":[{"id":"srv-tool-001","title":"Cryptographic Tool Manifests","description":"Every tool must have a signed manifest (RSA/ECDSA) that includes its description, schema, version, and required permissions. Verify this signature and hash at load time and on every invocation.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","input-validation","tool-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-002","title":"Tool Version Pinning & Rug Pull Prevention","description":"Pin approved tool versions using cryptographic hashes. Alert and block on any post-approval change to tool descriptions or behavior — this is the \\"rug pull\\" attack vector (post-approval descriptor mutations that subvert tool behavior).","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","tool-security","monitoring","governance","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-003","title":"Tool Description vs. Behavior Validation","description":"Validate that a tool's advertised description matches its actual runtime code behavior. Flag any tool performing actions (e.g., network writes, file reads) not mentioned in its manifest.","priority":"CRITICAL","roles":["architect","devops","developer"],"tags":["input-validation","tool-security","runtime-security","network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-004","title":"Tool Permission Control","description":"Each tool must only have the minimum permissions needed to complete its declared task.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","tool-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-005","title":"Strict Tool Onboarding & Approval","description":"Maintain a formal approval workflow (SAST, DAST, SCA, manual review) for adding or updating any tool or its description.","priority":"HIGH","roles":["developer"],"tags":["authorization","tool-security","governance","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-006","title":"Tool Isolation","description":"Execute tools in a controlled, sandboxed environment to prevent system-level impact or lateral movement.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["tool-security","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-007","title":"Tool Structure Validation","description":"Audit all fields of each tool. Expose only the minimal, strictly necessary fields to the model; keep internal metadata outside the model's context.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-008","title":"Namespace Isolation","description":"Enforce strict namespace isolation for different tools to prevent tool name hijacking or typosquatting.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["tool-security","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-009","title":"Tool Behavior Constraints","description":"Restrict the range and types of actions a tool can perform; define per-tool capability profiles.","priority":"HIGH","roles":["developer"],"tags":["tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-010","title":"Third-Party Interface Response Security","description":"Verify returned data from external interfaces matches expectations; never directly inject raw third-party responses into model context.","priority":"HIGH","roles":["security-engineer"],"tags":["prompt-injection","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-011","title":"Secure Error Handling","description":"Handle errors without exposing stack traces, tokens, filesystem paths, or tool internals to the model or client.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["authentication","tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-012","title":"Tool Classification","description":"Categorize tools by sensitivity and risk level; apply tiered review processes accordingly.","priority":"RECOMMENDED","roles":["developer"],"tags":["tool-security","governance","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-tool-013","title":"Tool Registration & Deregistration","description":"Define clear, audited processes for adding and removing tools to prevent orphaned or stale tool registrations.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["tool-security","monitoring","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Tools are executable capabilities exposed to AI. Without integrity verification, attackers can modify tool behavior, descriptions, or permissions post-approval."},{"id":"srv-data","number":"1.4","title":"Data Validation & Resource Management","items":[{"id":"srv-data-001","title":"Strict Input/Output Sanitization","description":"Treat all data as untrusted. Strip or escape sequences that could lead to XSS, SQL Injection, RCE, or path traversal. This applies to both inputs from the model and outputs returned to the model.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-002","title":"JSON Schema Enforcement","description":"Define and enforce JSON Schemas for every tool's inputs and outputs. Reject any request that doesn't match.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["input-validation","tool-security","runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-003","title":"Resource Usage Quotas","description":"Impose per-session quotas and rate limits on tool invocations and data fetches. Enforce timeouts and isolated memory/compute budgets to prevent DoS or runaway processes.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["tool-security","runtime-security","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-004","title":"Resource Access Control","description":"Implement fine-grained access control for resources exposed by the MCP server.","priority":"HIGH","roles":["security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-005","title":"Resource Limits","description":"Limit the size and quantity of individual resources returned.","priority":"HIGH","roles":["security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-006","title":"Resource Template Security","description":"Validate and sanitize all template parameters before use.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-007","title":"Sensitive Resource Labeling","description":"Label sensitive resources distinctly and apply specialized handling and access controls.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["runtime-security","privacy","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-data-901","title":"Input Normalization and Semantic Cross-Field Validation","description":"Normalize input values (for example Unicode canonicalization and case normalization) before validation, then enforce semantic and cross-field consistency checks to block evasion payloads that pass structural schema checks.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","data-security","priority-high"],"sources":[{"label":"Enterprise-Grade Security for MCP (arXiv:2504.08623v2)","url":"https://arxiv.org/abs/2504.08623v2"}]}],"description":"All data flowing through MCP must be validated and constrained. Uncontrolled inputs and outputs lead to injection, resource exhaustion, and context overflow."},{"id":"srv-prompt","number":"1.5","title":"Prompt Injection Controls","items":[{"id":"srv-prompt-001","title":"Structured Tool Invocation","description":"Favor structured JSON tool calls over free-form text commands. All model intent must flow through a schema-validated interface.","priority":"CRITICAL","roles":["developer"],"tags":["input-validation","tool-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-002","title":"Human-in-the-Loop (HITL) for High-Risk Actions","description":"For destructive or irreversible actions (deleting data, fund transfers, system-level changes), implement an approval checkpoint requiring explicit user confirmation (e.g., via MCP elicitations) before proceeding.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authorization","governance","crypto-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-003","title":"Indirect Prompt Injection Defense","description":"Sanitize all external data sources (web pages, documents, RAG content, emails, calendar events) before they can influence agent goals or tool calls. Apply CDR (Content Disarm & Reconstruction) and prompt-carrier detection.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","tool-security","runtime-security","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-004","title":"LLM-as-a-Judge for High-Risk Actions","description":"For high-risk tool calls, run a dedicated approval check in a distinct LLM session with a policy prompt defining which calls and parameters are allowed.","priority":"HIGH","roles":["compliance","architect","developer"],"tags":["authorization","prompt-injection","tool-security","governance","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-005","title":"Context Compartmentalization (One Task, One Session)","description":"Reset MCP sessions when an agent switches contexts or tasks to prevent hidden instructions from persisting in long conversation histories.","priority":"HIGH","roles":["architect"],"tags":["prompt-injection","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-006","title":"Tool Description Scanning","description":"Scan tool descriptions, parameters, and metadata for hidden instructions, invisible Unicode characters, or semantic manipulation attempts.","priority":"HIGH","roles":["developer"],"tags":["prompt-injection","tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-007","title":"Prompt Templates","description":"Use secure, parameterized prompt templates to reduce injection risk.","priority":"RECOMMENDED","roles":["developer"],"tags":["prompt-injection","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-prompt-008","title":"Prompt Consistency Verification","description":"Ensure identical prompts produce predictable and auditable results across environments.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["prompt-injection","monitoring","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Prompt injection is the most prevalent attack vector in AI systems. These controls prevent external data from hijacking agent goals or triggering unauthorized actions."},{"id":"srv-supply","number":"1.6","title":"Supply Chain Security","items":[{"id":"srv-supply-001","title":"Version Pinning & Checksums","description":"Pin all dependencies to exact versions with cryptographic checksums. Verify integrity at build and deploy time.","priority":"CRITICAL","roles":["security-engineer"],"tags":["tool-security","supply-chain","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-002","title":"Signed Container Images","description":"Use signed, immutable container images. Verify signatures before deployment.","priority":"CRITICAL","roles":["devops"],"tags":["runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-003","title":"Dependency Scanning (SCA)","description":"Integrate Software Composition Analysis tools (npm audit, pip audit, OSV-Scanner) into CI/CD. Block builds that introduce known-vulnerable dependencies.","priority":"HIGH","roles":["devops","developer","security-engineer"],"tags":["tool-security","supply-chain","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-004","title":"AIBOM (AI Bill of Materials)","description":"Maintain an AI Bill of Materials for all builds to ensure provenance and detect tampering.","priority":"HIGH","roles":["security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-005","title":"Source Verification","description":"Validate the origin and authenticity of all third-party code and packages. Only connect to servers from trusted, vetted registries.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["authentication","runtime-security","network-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-006","title":"Typosquatting Prevention","description":"Enforce fully qualified tool and package names. Fail closed on ambiguous name resolution.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-007","title":"Secure Build Pipeline","description":"Enforce integrity throughout the build process; use policy-as-code (e.g., OPA) to gate insecure dependencies.","priority":"HIGH","roles":["compliance","devops","developer","security-engineer"],"tags":["runtime-security","governance","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-008","title":"OpenSSF Scorecard","description":"Evaluate dependencies and repositories using the OpenSSF Scorecard to assess security posture.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["supply-chain","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-supply-009","title":"CVE Monitoring","description":"Continuously monitor OSV and NVD for new vulnerabilities in dependencies.","priority":"RECOMMENDED","roles":["devops","security-engineer"],"tags":["supply-chain","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"MCP servers depend on third-party packages and container images. Compromised dependencies introduce backdoors, credential theft, and supply chain attacks."},{"id":"srv-runtime","number":"1.7","title":"Deployment & Runtime Security","items":[{"id":"srv-runtime-001","title":"Containerization & Hardening","description":"Deploy MCP servers in minimal, hardened containers running as non-root users. Drop all unnecessary Linux capabilities.","priority":"CRITICAL","roles":["devops"],"tags":["runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-002","title":"Secrets Vaulting","description":"Store all credentials, API keys, and tokens in a secrets vault. Never store secrets in environment variables, logs, or plaintext in code. Never allow the LLM access to secrets directly; use opaque middleware.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authentication","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-003","title":"Network Segmentation","description":"Place the server in a restricted network segment. Use firewall rules or Kubernetes NetworkPolicies to block all traffic except what is explicitly required.","priority":"CRITICAL","roles":["architect","devops"],"tags":["network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-004","title":"CI/CD Security Gates","description":"Integrate security scanning as a mandatory build gate. Fail builds that introduce vulnerabilities, unapproved dependencies, or policy violations.","priority":"CRITICAL","roles":["compliance","devops","security-engineer"],"tags":["priority-critical","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-005","title":"Isolation Environment","description":"Run servers in isolated environments (containers, VMs, or sandboxes) to prevent escape and mitigate lateral movement.","priority":"HIGH","roles":["architect","devops","security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-006","title":"Environment Variable Protection","description":"Ensure sensitive environment variables are not exposed in logs, error messages, or stack traces.","priority":"HIGH","roles":["security-engineer"],"tags":["privacy","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-007","title":"Secure Boot","description":"Validate service boot processes with integrity checks.","priority":"HIGH","roles":["security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-008","title":"RCE Primitive Controls","description":"Secure or disable execute primitives (git hooks, smudge/clean filters, aliases, post-checkout scripts) that can be abused for arbitrary code execution.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-009","title":"SSRF Prevention","description":"Validate and restrict all outbound network calls from tools; use egress allowlists to block Server-Side Request Forgery vectors. (30% of MCP servers are vulnerable to SSRF.)","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["authorization","tool-security","network-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-010","title":"Immutable Infrastructure","description":"Adopt immutable infrastructure patterns; containers should not be modified in place after deployment.","priority":"RECOMMENDED","roles":["devops"],"tags":["runtime-security","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-runtime-011","title":"Secure Protocol Configuration","description":"Configure TLS with modern parameters; regularly review and update cipher suites.","priority":"RECOMMENDED","roles":["architect"],"tags":["network-security","governance","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Runtime environment configuration determines the blast radius of any breach. Hardened containers, network segmentation, and secrets management limit attacker movement."},{"id":"srv-persist","number":"1.8","title":"Background Persistence Control","items":[{"id":"srv-persist-001","title":"Lifecycle Management","description":"Implement strict lifecycle management for MCP plugins; coordinate termination with the client.","priority":"HIGH","roles":["security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-persist-002","title":"Shutdown Cleanup (Deterministic)","description":"On session termination, disconnect, or timeout, immediately flush and destroy all associated file handles, temporary storage, in-memory contexts, and cached tokens.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["authentication","prompt-injection","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-persist-003","title":"Background Activity Monitoring","description":"Monitor and log all MCP background activities; alert on anomalous persistence.","priority":"HIGH","roles":["devops"],"tags":["monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-persist-004","title":"Activity Restrictions","description":"Limit the operations and duration of MCP background processes.","priority":"HIGH","roles":["security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-persist-005","title":"Health Check Mechanism","description":"Regularly check the status of MCP plugins to detect abnormal persistence or zombie processes.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["priority-recommended","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"MCP plugins that persist after session end can maintain unauthorized access. Lifecycle controls ensure clean termination and prevent zombie processes."},{"id":"srv-monitor","number":"1.9","title":"Monitoring & Logging","items":[{"id":"srv-monitor-001","title":"Comprehensive Audit Logs","description":"Log every action — tool invocations (with parameters), resource access, authentication/authorization events, and configuration changes (logging old and new values). Use field-level allowlists and redaction/hashing to prevent sensitive data from appearing in verbose logs.","priority":"CRITICAL","roles":["devops","developer","security-engineer"],"tags":["authentication","authorization","tool-security","runtime-security","monitoring","privacy","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-monitor-002","title":"Immutable Log Storage","description":"Store logs securely and immutably for forensic analysis. Ensure log integrity; prevent tampering.","priority":"CRITICAL","roles":["security-engineer"],"tags":["monitoring","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-monitor-003","title":"Centralized SIEM Integration","description":"Feed MCP server audit logs into a centralized monitoring system (SIEM). Configure real-time alerts for suspicious patterns (spike in failed validations, high-frequency tool calls, unusual file access).","priority":"HIGH","roles":["devops","developer","security-engineer"],"tags":["input-validation","tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-monitor-004","title":"Anomaly Detection","description":"Detect and alert on abnormal tool invocation patterns (mass file reads, excessive API calls, unusual chaining).","priority":"HIGH","roles":["developer"],"tags":["tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-monitor-005","title":"Security Event Alerts","description":"Configure real-time alerts for critical security events (auth failures, schema violations, unexpected tool behavior).","priority":"HIGH","roles":["developer","security-engineer"],"tags":["authentication","input-validation","tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-monitor-006","title":"Behavioral Baseline","description":"Establish a behavioral baseline for normal tool-use patterns and alert on deviations.","priority":"RECOMMENDED","roles":["developer"],"tags":["tool-security","monitoring","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-monitor-901","title":"End-to-End Request Tracing Across Tool Chains","description":"Implement distributed tracing across authentication, policy checks, MCP calls, and downstream tool invocations so each high-risk action has a complete lineage for detection, forensics, and incident response.","priority":"HIGH","roles":["security-engineer","devops","architect"],"tags":["monitoring","audit-logging","incident-response","priority-high"],"sources":[{"label":"Enterprise-Grade Security for MCP (arXiv:2504.08623v2)","url":"https://arxiv.org/abs/2504.08623v2"}]}],"description":"Without comprehensive audit trails, security incidents cannot be detected, investigated, or attributed. Monitoring provides the evidence chain for incident response."},{"id":"srv-privacy","number":"1.10","title":"Data Security & Privacy","items":[{"id":"srv-privacy-001","title":"Data Encryption","description":"Encrypt sensitive data both in storage and in transit (TLS 1.2+ minimum).","priority":"CRITICAL","roles":["security-engineer"],"tags":["network-security","privacy","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-privacy-002","title":"Data Minimization","description":"Collect and process only the data necessary for the task.","priority":"HIGH","roles":["security-engineer"],"tags":["privacy","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-privacy-003","title":"Data Isolation","description":"Ensure effective isolation of different users' data. No shared mutable state across sessions or users.","priority":"HIGH","roles":["architect"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-privacy-004","title":"Sensitive Data Identification","description":"Automatically identify and apply specialized handling for sensitive data (PII, credentials, financial data).","priority":"HIGH","roles":["security-engineer"],"tags":["privacy","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-privacy-005","title":"Data Access Control","description":"Enforce strict, auditable access controls on all stored data.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["runtime-security","monitoring","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Data handled by MCP servers may include PII, credentials, and financial information. Encryption, minimization, and isolation prevent unauthorized exposure."},{"id":"srv-resource","number":"1.11","title":"Resources Security","items":[{"id":"srv-resource-001","title":"Resource Access Control","description":"Implement fine-grained access control for each resource type.","priority":"HIGH","roles":["security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-resource-002","title":"Resource Size & Count Limits","description":"Limit the size and number of resources per session to prevent abuse.","priority":"HIGH","roles":["architect","security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"srv-resource-003","title":"Resource Template Security","description":"Validate and sanitize all template parameters before materializing resources.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["input-validation","runtime-security","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Resources exposed by MCP servers must be access-controlled and size-limited to prevent data exfiltration and abuse through unrestricted resource access."}],"whyItMatters":"The MCP Server provides external tools, resources, and functionalities that AI can invoke. It is the primary attack surface in the MCP ecosystem."},{"id":"mcp-client","title":"MCP Client / Host Security","icon":"Monitor","description":"Host and client protections for safe server interactions, user approvals, and secure operation flows.","number":2,"subsections":[{"id":"cli-ui","number":"2.1","title":"User Interaction Security","items":[{"id":"cli-ui-001","title":"Full Tool Transparency","description":"Display the complete tool manifest (descriptions, parameters, capabilities, permissions) to users before activation. Never display shortened summaries that can hide injected instructions — including hidden tags like <SECRET>.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","prompt-injection","tool-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-ui-002","title":"Confirmation of Sensitive Operations","description":"High-risk operations (file deletion, fund transfers, system commands) must require explicit, informed user confirmation.","priority":"CRITICAL","roles":["security-engineer"],"tags":["privacy","crypto-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-ui-003","title":"Operation Visualization","description":"Make tool invocations and data access visible and auditable by users with detailed operation logs.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-ui-004","title":"Permission Request Transparency","description":"Permission requests must explicitly state their purpose and scope to prevent over-authorization.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","authorization","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-ui-005","title":"Status Feedback","description":"Users should have real-time visibility into what MCP operations are currently in progress.","priority":"HIGH","roles":["security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-ui-006","title":"UI Security Indicators","description":"Provide intuitive security indicators in the UI showing the scope of AI operations.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["authorization","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Users are the final defense against malicious tool behavior. Full transparency into tool operations prevents hidden actions and social engineering attacks."},{"id":"cli-auth","number":"2.2","title":"Client Authentication & Authorization","items":[{"id":"cli-auth-001","title":"Mandatory Authentication","description":"Enforce authentication before communicating with any MCP Server; prohibit anonymous access.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","runtime-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-auth-002","title":"OAuth 2.1 / PKCE Implementation","description":"Implement OAuth 2.1 with PKCE correctly for user-facing operations. Use client credentials for system-to-system operations.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-auth-003","title":"CSRF Protection","description":"For web-based clients, use a unique random state parameter per request to mitigate CSRF attacks.","priority":"HIGH","roles":["security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-auth-004","title":"Minimal OAuth Scopes","description":"Restrict access using minimal, task-specific OAuth scopes. Use action-level permissions on a per-identity basis.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","authorization","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-auth-005","title":"Short-Lived PATs","description":"Where OAuth cannot be implemented, use narrowly scoped, short-lived Personal Access Tokens.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["authentication","authorization","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-auth-901","title":"Risk-Based Step-Up Authentication with Live Revocation","description":"Continuously reassess risk during active sessions and require step-up authentication for sensitive tool actions, with immediate revocation of temporary grants when risk posture changes.","priority":"HIGH","roles":["security-engineer","architect","developer"],"tags":["authentication","zero-trust","client-security","priority-high"],"sources":[{"label":"Enterprise-Grade Security for MCP (arXiv:2504.08623v2)","url":"https://arxiv.org/abs/2504.08623v2"}]}],"description":"Client authentication establishes identity before any server communication. Without it, anonymous clients can access sensitive tools and data."},{"id":"cli-verify","number":"2.3","title":"Server Verification & Communication Security","items":[{"id":"cli-verify-001","title":"TLS 1.2+ Enforcement","description":"Encrypt all Client-Server communications with TLS 1.2+. Disable weak cipher suites.","priority":"CRITICAL","roles":["security-engineer"],"tags":["runtime-security","network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-verify-002","title":"Certificate Validation","description":"Strictly validate TLS certificates of remote Servers; check the full certificate chain. Implement certificate pinning where feasible.","priority":"CRITICAL","roles":["developer"],"tags":["authentication","input-validation","network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-verify-003","title":"Server Identity Verification","description":"Verify MCP Server identity before connecting; prevent connections to impersonated or malicious servers.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-verify-004","title":"Origin Header Validation","description":"For local HTTP connections, validate the Origin header to prevent cross-site request forgery.","priority":"HIGH","roles":["developer"],"tags":["input-validation","network-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-verify-005","title":"JSON-RPC Schema Validation","description":"Strictly validate all JSON-RPC messages against the MCP schema; reject malformed or unrecognized data.","priority":"HIGH","roles":["developer"],"tags":["input-validation","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-verify-006","title":"Trusted Registry Only","description":"Only connect to servers from a vetted, internal registry. Use IP allowlists and network isolation.","priority":"RECOMMENDED","roles":["architect"],"tags":["authorization","supply-chain","network-security","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Clients must verify they are communicating with legitimate servers. Without verification, man-in-the-middle attacks and server impersonation go undetected."},{"id":"cli-manage","number":"2.4","title":"MCP Tools & Servers Management","items":[{"id":"cli-manage-001","title":"Tool Version Pinning","description":"Maintain a manifest of approved server and tool versions with checksums. Alert on any unauthorized changes.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authentication","tool-security","supply-chain","monitoring","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-002","title":"Malicious MCP Detection","description":"Monitor and identify potentially malicious MCP behavior; scan installed MCPs periodically.","priority":"CRITICAL","roles":["devops"],"tags":["priority-critical","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-003","title":"Function Name Conflict Prevention","description":"Check for name conflicts or malicious overwriting before registering any tool. Use namespaces or unique identifiers.","priority":"HIGH","roles":["developer"],"tags":["tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-004","title":"Secure Update Verification","description":"Regularly check for and apply security updates; verify that updated tools do not contain malicious descriptions.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-005","title":"Conflict Resolution","description":"Establish clear, audited rules to resolve tool name conflicts and malicious priority hijacking.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-006","title":"Domain Isolation","description":"Isolate tools across different domains to prevent cross-domain impact.","priority":"HIGH","roles":["architect","developer"],"tags":["tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-007","title":"Tool Classification","description":"Classify tools by sensitivity and risk level; apply tiered approval for high-risk tools.","priority":"HIGH","roles":["developer"],"tags":["authorization","tool-security","governance","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-008","title":"Staged Rollout","description":"Deploy new servers in staging with full telemetry; promote to production only after a probation period with no incidents.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["priority-recommended","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-manage-009","title":"Authorized Server Directory","description":"Maintain a central directory of all approved MCP servers and tools.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["authentication","tool-security","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Managing which tools and servers are active prevents exposure to malicious or outdated components. Version control and conflict resolution reduce attack surface."},{"id":"cli-prompt","number":"2.5","title":"Prompt Security","items":[{"id":"cli-prompt-001","title":"Prompt Injection Defense","description":"Implement layered defenses against prompt injection, including manual verification for critical executions. Detect preloaded malicious prompts at initialization.","priority":"CRITICAL","roles":["developer"],"tags":["prompt-injection","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-002","title":"System Prompt Protection","description":"Clearly separate system prompts from user inputs; prevent tampering or override.","priority":"CRITICAL","roles":["developer"],"tags":["input-validation","prompt-injection","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-003","title":"Malicious Instruction Detection","description":"Detect and block malicious instructions embedded in tool descriptions, tool outputs, and third-party MCP server responses.","priority":"CRITICAL","roles":["developer"],"tags":["input-validation","prompt-injection","tool-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-004","title":"Sensitive Data Filtering","description":"Filter sensitive personal data from prompts and context before sending to models or third-party services.","priority":"HIGH","roles":["developer"],"tags":["prompt-injection","privacy","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-005","title":"Context Isolation","description":"Ensure contexts from different sources remain isolated; prevent cross-contamination or information leakage between sessions.","priority":"HIGH","roles":["architect","security-engineer"],"tags":["prompt-injection","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-006","title":"Historical Context Management","description":"Define and enforce a clear mechanism for cleaning up historical context to prevent data buildup and stale injection risks.","priority":"HIGH","roles":["security-engineer"],"tags":["prompt-injection","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-007","title":"Prompt Templates","description":"Use secure, parameterized prompt templates to reduce injection risk.","priority":"RECOMMENDED","roles":["developer"],"tags":["prompt-injection","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-prompt-008","title":"Prompt Consistency Verification","description":"Verify that identical prompts produce predictable, consistent results across environments.","priority":"RECOMMENDED","roles":["developer"],"tags":["prompt-injection","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Prompts are the control plane for AI behavior. Prompt injection, context contamination, and instruction override can redirect agent actions entirely."},{"id":"cli-audit","number":"2.6","title":"Logging & Auditing","items":[{"id":"cli-audit-001","title":"Client-Side Logging","description":"Record all interactions with MCP Servers, tool calls, and authorization activities.","priority":"CRITICAL","roles":["devops","developer","security-engineer"],"tags":["authentication","tool-security","monitoring","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-audit-002","title":"Security Event Recording","description":"Log all security-related events, including authorization failures and anomalous invocations.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-audit-003","title":"Anomaly Alerts","description":"Alert on abnormal tool invocation patterns (mass file reads, excessive API calls, unusual chaining sequences).","priority":"HIGH","roles":["developer"],"tags":["tool-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Client-side logs capture the full picture of interactions that server logs may miss. They are essential for detecting compromised servers and anomalous patterns."},{"id":"cli-token","number":"2.7","title":"Permission Token Storage & Management","items":[{"id":"cli-token-001","title":"Secure Credential Storage","description":"Use the system keychain or dedicated encrypted storage for sensitive credentials; prevent unauthorized access.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","privacy","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-token-002","title":"Permission Scope Limitation","description":"Strictly limit token scopes; enforce least privilege at the token level.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","authorization","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-token-003","title":"Sensitive Data Isolation","description":"Isolate sensitive user data from ordinary data in storage and processing.","priority":"HIGH","roles":["architect"],"tags":["privacy","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Stored tokens and credentials are high-value targets. Secure storage with scope limitation prevents token theft and privilege escalation."},{"id":"cli-approve","number":"2.8","title":"Auto-Approve Control","items":[{"id":"cli-approve-001","title":"Auto-Approve Restrictions","description":"Carefully control which tools and operations qualify for auto-approval; default to requiring human review for novel or high-risk actions.","priority":"CRITICAL","roles":["developer"],"tags":["authorization","tool-security","governance","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-approve-002","title":"Whitelist Management","description":"Maintain and audit a whitelist of tools eligible for auto-approval.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["authorization","tool-security","monitoring","governance","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-approve-003","title":"Approval Process Auditing","description":"Log and audit all auto-approval decisions.","priority":"HIGH","roles":["security-engineer"],"tags":["authorization","monitoring","governance","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-approve-004","title":"Dynamic Risk Assessment","description":"Dynamically adjust auto-approval policies based on session context and risk signals.","priority":"RECOMMENDED","roles":["architect"],"tags":["authorization","prompt-injection","governance","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Auto-approval bypasses human oversight. Without careful control, malicious tools can execute destructive actions without user awareness."},{"id":"cli-sample","number":"2.9","title":"Sampling Security","items":[{"id":"cli-sample-001","title":"Context Scope Control","description":"Strictly control which context is included in sampling requests; apply minimum necessary context.","priority":"HIGH","roles":["security-engineer"],"tags":["authorization","prompt-injection","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-sample-002","title":"Sensitive Data Filtering in Sampling","description":"Filter out sensitive data from sampling requests and responses.","priority":"HIGH","roles":["security-engineer"],"tags":["privacy","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-sample-003","title":"Sampling Request Validation","description":"Validate all parameters and content within sampling requests.","priority":"HIGH","roles":["developer"],"tags":["input-validation","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-sample-004","title":"User Control over Sampling","description":"Ensure users have clear, auditable control over sampling requests and results.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["monitoring","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cli-sample-005","title":"Result Validation","description":"Verify that sampling results conform to expected security and quality standards.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["input-validation","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Sampling requests can leak sensitive context to models. Controlling what data enters sampling prevents unintended information disclosure."}],"whyItMatters":"The Host is the AI application environment; the Client communicates with MCP Servers. Both are first-line defenses against malicious server behavior."},{"id":"architecture","title":"Secure MCP Architecture","icon":"Network","description":"Architecture-level controls for transport security, identity boundaries, and multi-MCP risk containment.","number":3,"subsections":[{"id":"arc-net","number":"3.1","title":"Transport & Network Security","items":[{"id":"arc-net-001","title":"Local MCP — Prefer STDIO/Unix Sockets","description":"For local MCP servers, use STDIO or Unix sockets over network sockets. If local HTTP is required, bind only to 127.0.0.1, validate the Origin header, and still enforce authentication.","priority":"CRITICAL","roles":["architect","security-engineer"],"tags":["authentication","runtime-security","network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-net-002","title":"Remote MCP — Enforce TLS 1.2+","description":"All remote MCP server connections must use TLS 1.2 or higher.","priority":"CRITICAL","roles":["security-engineer"],"tags":["runtime-security","network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-net-003","title":"Mutual TLS (mTLS) for Static Relationships","description":"For known, static client-server relationships, use mTLS to provide bidirectional identity verification.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","network-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-net-004","title":"WAF & Rate Limiting for Remote Endpoints","description":"Protect remote MCP servers with a Web Application Firewall and rate limiters.","priority":"HIGH","roles":["security-engineer"],"tags":["network-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-net-005","title":"Egress Allowlists","description":"Enforce strict outbound traffic controls; deny all non-approved network destinations from tool execution environments.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["authorization","tool-security","runtime-security","network-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Transport security is the foundation of all MCP communication. Unencrypted or weakly authenticated channels expose every message to interception and tampering."},{"id":"arc-session","number":"3.2","title":"Session & Identity Isolation","items":[{"id":"arc-session-001","title":"Per-Session Isolation","description":"Strictly segregate execution contexts, memory, and temporary storage for each user or agent session. Prohibit global variables or shared singletons for user-specific data.","priority":"CRITICAL","roles":["architect","developer"],"tags":["prompt-injection","agentic-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-session-002","title":"Per-Session Resource Quotas","description":"Enforce strict limits on memory, CPU, filesystem usage, and API rate limits per session ID or user identity.","priority":"CRITICAL","roles":["architect","developer","security-engineer"],"tags":["authentication","runtime-security","agentic-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-session-003","title":"Deterministic Session Cleanup","description":"When an MCP session terminates, disconnects, or times out, immediately destroy all associated file handles, temporary storage, in-memory contexts, and cached tokens.","priority":"CRITICAL","roles":["architect","developer","security-engineer"],"tags":["authentication","prompt-injection","agentic-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-session-004","title":"Non-Human Identity (NHI) Governance","description":"Treat all automated agents, backend processes, and MCP server systems as first-class identities with unique credentials and tightly scoped permissions. Continuously audit NHI systems.","priority":"HIGH","roles":["compliance","security-engineer"],"tags":["authentication","authorization","monitoring","governance","agentic-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-session-005","title":"Cross-Tenant Isolation","description":"Implement protocol-enforced state separation in multi-tenant deployments to prevent cross-tenant data leakage.","priority":"HIGH","roles":["architect","devops","security-engineer"],"tags":["runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Session isolation prevents cross-user data leakage. Without it, one user's data, tokens, and context can be accessed by another user or agent."},{"id":"arc-multi","number":"3.3","title":"Multi-MCP Scenario Security","items":[{"id":"arc-multi-001","title":"Cross-MCP Function Call Control","description":"Secure control over cross-MCP function calls to prevent malicious MCP servers from returning harmful prompts that trigger other MCPs into performing sensitive operations. (72.4% documented cascade rate between compromised servers.)","priority":"CRITICAL","roles":["developer"],"tags":["prompt-injection","privacy","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-multi-002","title":"Multi-MCP Environment Scanning","description":"Periodically scan and inspect all installed MCPs in multi-server environments.","priority":"CRITICAL","roles":["security-engineer"],"tags":["priority-critical","mcp-security"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-multi-003","title":"Server Isolation Policies","description":"Data flow between MCP servers must require explicit, policy-enforced authorization.","priority":"HIGH","roles":["compliance","architect","security-engineer"],"tags":["authentication","runtime-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-multi-004","title":"Shared Context Contamination Prevention","description":"Prevent tools from one MCP server from poisoning the context of another.","priority":"HIGH","roles":["developer"],"tags":["prompt-injection","tool-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-multi-005","title":"Combined Capability Mapping","description":"Document and audit all server combinations (e.g., Git + Browser, Filesystem + Network) for compound attack surfaces.","priority":"HIGH","roles":["architect","security-engineer"],"tags":["network-security","monitoring","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-multi-006","title":"Function Priority Hijacking Prevention","description":"Check for malicious prompt presets designed to hijack function call priority.","priority":"RECOMMENDED","roles":["developer"],"tags":["prompt-injection","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"arc-multi-901","title":"Capability Discovery Allowlisting","description":"Restrict capability discovery so clients can enumerate and invoke tools only from explicitly approved MCP servers and namespaces, preventing cross-server spoofing and unauthorized capability expansion.","priority":"HIGH","roles":["architect","security-engineer","developer"],"tags":["multi-mcp","authorization","tool-security","priority-high"],"sources":[{"label":"Enterprise-Grade Security for MCP (arXiv:2504.08623v2)","url":"https://arxiv.org/abs/2504.08623v2"}]}],"description":"Multiple MCP servers in one environment create compound attack surfaces. A compromised server can cascade attacks to others through shared context or function calls."}]},{"id":"agentic","title":"Agentic-Specific Security","icon":"Bot","description":"OWASP ASI01–ASI10 controls for agent goal safety, tool abuse prevention, and resilient autonomous workflows.","number":4,"subsections":[{"id":"agn-hijack","number":"4.1","title":"Agent Goal Hijack Prevention (ASI01)","items":[{"id":"agn-hijack-001","title":"Treat All Natural-Language Inputs as Untrusted","description":"Route user-provided text, uploaded documents, and retrieved external content through input-validation and prompt-injection safeguards before they can influence goal selection, planning, or tool calls.","priority":"CRITICAL","roles":["developer"],"tags":["input-validation","prompt-injection","tool-security","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-hijack-002","title":"Lock Agent System Prompts","description":"Define and lock system prompts so that goal priorities and permitted actions are explicit and auditable. Changes must go through configuration management and human approval.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","prompt-injection","monitoring","governance","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-hijack-003","title":"Validate User Intent & Agent Intent at Runtime","description":"Require confirmation via human approval, policy engine, or guardrails whenever an agent proposes actions deviating from the original task or scope.","priority":"HIGH","roles":["compliance","devops"],"tags":["authorization","runtime-security","network-security","governance","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-hijack-004","title":"Sanitize Connected Data Sources","description":"Sanitize RAG inputs, emails, calendar invites, uploaded files, external APIs, browsing output, and peer-agent messages using CDR and content filtering.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","runtime-security","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-hijack-005","title":"Behavioral Baseline & Goal Drift Alerting","description":"Track a stable identifier for the active goal; alert on unexpected goal changes, anomalous tool sequences, or shifts from the established behavioral baseline.","priority":"HIGH","roles":["developer"],"tags":["tool-security","monitoring","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-hijack-006","title":"Periodic Red-Team Testing","description":"Conduct periodic red-team simulations of goal override attacks and verify rollback effectiveness.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-hijack-007","title":"Intent Capsule Pattern","description":"Bind declared goals, constraints, and context to each execution cycle in a signed, immutable envelope to restrict runtime modification.","priority":"RECOMMENDED","roles":["devops","developer"],"tags":["prompt-injection","runtime-security","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Agent goal hijacking redirects autonomous systems to attacker-controlled objectives. Locked system prompts and validated inputs prevent goal drift and override."},{"id":"agn-misuse","number":"4.2","title":"Tool Misuse & Exploitation Prevention (ASI02)","items":[{"id":"agn-misuse-001","title":"Least Agency & Least Privilege for Tools","description":"Define per-tool least-privilege profiles (scopes, maximum call rate, egress allowlists). Restrict tool functionality and data access to those profiles (e.g., read-only DB queries, no send/delete rights for email summarizers).","priority":"CRITICAL","roles":["developer"],"tags":["authorization","tool-security","network-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-misuse-002","title":"Action-Level Authentication & Approval","description":"Require explicit authentication for each tool invocation and human confirmation for high-impact or destructive actions (delete, transfer, publish). Present a dry-run or diff preview before approval.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authentication","authorization","tool-security","governance","crypto-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-misuse-003","title":"Policy Enforcement Middleware (\\"Intent Gate\\")","description":"Treat LLM/planner outputs as untrusted. A pre-execution Policy Enforcement Point (PEP/PDP) validates intent and arguments, enforces schemas and rate limits, and issues short-lived credentials.","priority":"HIGH","roles":["compliance","developer","security-engineer"],"tags":["input-validation","runtime-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-misuse-004","title":"Tool Sandboxing & Egress Controls","description":"Run tool execution in isolated sandboxes. Enforce outbound allowlists; deny all non-approved network destinations.","priority":"HIGH","roles":["architect","developer","security-engineer"],"tags":["authorization","tool-security","runtime-security","network-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-misuse-005","title":"Adaptive Tool Budgeting","description":"Apply cost, rate, or token usage ceilings with automatic throttling or revocation when exceeded.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["authentication","tool-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-misuse-006","title":"Semantic Firewalls","description":"Enforce fully qualified tool names and version pins to avoid typosquatted or alias-colliding tools. Fail closed on ambiguous name resolution.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","runtime-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-misuse-007","title":"Just-in-Time (JIT) Ephemeral Access","description":"Grant temporary credentials or API tokens that expire immediately after use, bound to specific user sessions.","priority":"RECOMMENDED","roles":["architect","developer","security-engineer"],"tags":["authentication","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Tools are the hands of the agent. Without least-privilege profiles and approval gates, a compromised agent can delete data, transfer funds, or exfiltrate secrets."},{"id":"agn-identity","number":"4.3","title":"Identity & Privilege Abuse Prevention (ASI03)","items":[{"id":"agn-identity-001","title":"Governed Agent Identities","description":"Every agent must have a distinct, governed identity (unique credentials, tightly scoped permissions). Prevent unscoped privilege inheritance from manager agents to worker agents.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","authorization","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-identity-002","title":"Prevent Memory-Based Credential Retention","description":"Agents must not cache credentials, keys, or retrieved sensitive data across tasks or users. Clear agent memory between session boundaries.","priority":"CRITICAL","roles":["architect","developer"],"tags":["privacy","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-identity-003","title":"Token Delegation with Minimal Scope","description":"Use the OAuth token delegation flow (RFC 8693) to pass user context while limiting permissions. Maintain distinct server non-human identities.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","authorization","prompt-injection","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-identity-004","title":"Prevent Confused Deputy Attacks","description":"Ensure the MCP server cannot be tricked into misusing a user's privileges to execute unauthorized actions on their behalf.","priority":"HIGH","roles":["security-engineer"],"tags":["authentication","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-identity-005","title":"MFA for High-Privilege Agent Actions","description":"Require multi-factor authentication for agents initiating high-privilege operations.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["authentication","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Agent identities control what each agent can access. Shared or inherited credentials allow privilege escalation and confused deputy attacks across agent hierarchies."},{"id":"agn-supply","number":"4.4","title":"Agentic Supply Chain Security (ASI04)","items":[{"id":"agn-supply-001","title":"Vet Third-Party Agent Components","description":"Treat all external agent frameworks, tool libraries, and MCP server packages as untrusted until formally reviewed and approved.","priority":"CRITICAL","roles":["developer"],"tags":["tool-security","governance","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-supply-002","title":"AIBOM for Agent Stacks","description":"Maintain an AI Bill of Materials covering all agent dependencies, model weights, and tool definitions.","priority":"HIGH","roles":["developer"],"tags":["tool-security","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-supply-003","title":"Monitor for Malicious MCP Packages","description":"Actively monitor registries for typosquatted or backdoored MCP server packages (e.g., the Postmark MCP impersonation incident, Sep 2025).","priority":"HIGH","roles":["devops","security-engineer"],"tags":["priority-high","mcp-security"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}],"incidentRefs":["Postmark MCP impersonation incident, Sep 2025"]},{"id":"agn-supply-004","title":"Signed Artifacts Throughout","description":"Sign all agent code artifacts, tool manifests, and model weights in the deployment pipeline.","priority":"RECOMMENDED","roles":["devops","developer"],"tags":["tool-security","supply-chain","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Agentic supply chains include tool libraries, model weights, and MCP packages. Unvetted components introduce backdoors and malicious behavior into agent workflows."},{"id":"agn-rce","number":"4.5","title":"Unexpected Code Execution / RCE Prevention (ASI05)","items":[{"id":"agn-rce-001","title":"Sandbox All Code Execution","description":"Execute all model-generated or tool-triggered code inside isolated sandboxes (containers, micro-VMs). Apply seccomp profiles, AppArmor, or equivalent.","priority":"CRITICAL","roles":["devops","developer","security-engineer"],"tags":["tool-security","runtime-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-rce-002","title":"Disable Dangerous Execution Primitives","description":"Secure or disable git hooks, smudge/clean filters, aliases, shell expansion, and similar RCE vectors in tool implementations.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["tool-security","runtime-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-rce-003","title":"Input Validation Before Shell Invocation","description":"Never pass model-provided or user-provided strings directly to shell commands without thorough validation and allowlist-based filtering.","priority":"HIGH","roles":["developer"],"tags":["authorization","input-validation","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-rce-004","title":"Allowlist-Based Execution","description":"Define an explicit allowlist of permitted operations; deny everything else by default.","priority":"HIGH","roles":["developer"],"tags":["authorization","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Agents may trigger code execution through tools or model outputs. Without sandboxing, this creates remote code execution vulnerabilities in the host environment."},{"id":"agn-memory","number":"4.6","title":"Memory & Context Poisoning Prevention (ASI06)","items":[{"id":"agn-memory-001","title":"Validate Memory Updates","description":"Enforce validation on every memory write. Require source attribution, scan for anomalies, and use cryptographic integrity checks (hashes) on stored context.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["input-validation","prompt-injection","runtime-security","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-memory-002","title":"Memory Segmentation by Session/User","description":"Prevent agents from writing to a shared memory store. Isolate memory by session or user identity to prevent cascading poisoning.","priority":"CRITICAL","roles":["architect","developer"],"tags":["authentication","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-memory-003","title":"TTL on Stored Memory","description":"Implement Time-To-Live on all stored agent data to prevent outdated or malicious information from persisting indefinitely.","priority":"HIGH","roles":["developer"],"tags":["agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-memory-004","title":"RAG Retrieval Validation","description":"Validate and sanitize all documents retrieved from vector databases or RAG pipelines before injecting them into model context.","priority":"HIGH","roles":["devops","developer"],"tags":["input-validation","prompt-injection","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-memory-005","title":"Memory Access Auditing","description":"Log all reads and writes to agent memory; alert on anomalous patterns.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["monitoring","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Agent memory persists across interactions. Poisoned memory can alter future decisions, inject false context, and cascade misinformation through RAG pipelines."},{"id":"agn-inter","number":"4.7","title":"Inter-Agent Communication Security (ASI07)","items":[{"id":"agn-inter-001","title":"Authenticate Agent-to-Agent Messages","description":"All inter-agent messages must be authenticated and integrity-verified. Do not trust messages from agents claiming high-trust status without cryptographic verification.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","agentic-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-inter-002","title":"Prevent Role Contamination","description":"Isolate agent roles and responsibilities; prevent one agent from inheriting or overriding another's role or permissions through message passing.","priority":"HIGH","roles":["security-engineer"],"tags":["authorization","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-inter-003","title":"Validate Agent Cards / Directories","description":"When using agent discovery (e.g., A2A protocol), verify agent identity claims in directories; reject unverified high-trust claims (guard against \\"Agent-in-the-Middle\\" attacks).","priority":"HIGH","roles":["architect","security-engineer"],"tags":["authentication","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-inter-004","title":"Structured Message Schemas","description":"Enforce strict schemas for all inter-agent messages; reject anything outside the defined schema.","priority":"RECOMMENDED","roles":["developer","security-engineer"],"tags":["input-validation","runtime-security","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Inter-agent messages can carry malicious payloads. Without authentication and schema validation, one compromised agent can subvert an entire multi-agent system."},{"id":"agn-cascade","number":"4.8","title":"Cascading Failure Prevention (ASI08)","items":[{"id":"agn-cascade-001","title":"Circuit Breakers","description":"Implement circuit breakers for all tool chains and downstream dependencies to prevent runaway cascades.","priority":"CRITICAL","roles":["developer"],"tags":["tool-security","priority-critical"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-cascade-002","title":"Timeout Policies","description":"Enforce execution timeouts for all tool calls and agent actions; prevent blocking or loop amplification.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","runtime-security","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-cascade-003","title":"Blast Radius Limitation","description":"Design agent workflows to minimize blast radius; limit the set of downstream systems any single agent can affect.","priority":"HIGH","roles":["security-engineer"],"tags":["governance","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-cascade-004","title":"Graceful Degradation","description":"Design MCP integrations to degrade gracefully; document safe fallback behaviors for all failure modes.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["priority-recommended","mcp-security"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Cascading failures amplify single-point compromises into system-wide outages. Circuit breakers and timeout policies contain blast radius and prevent runaway chains."},{"id":"agn-trust","number":"4.9","title":"Human-Agent Trust Exploitation Prevention (ASI09)","items":[{"id":"agn-trust-001","title":"Validate Agent-Presented Actions","description":"Implement checks to ensure agents cannot deceive human operators into approving harmful actions through misleading summaries or false confirmations.","priority":"HIGH","roles":["security-engineer"],"tags":["agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-trust-002","title":"Audit AI Output Trustworthiness","description":"Independently verify critical AI-generated outputs before using them in consequential decisions; do not rely solely on agent-provided evidence.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","monitoring","agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-trust-003","title":"Insider Threat Integration","description":"Incorporate AI agents into the established Insider Threat Program to monitor insider prompts intended to access sensitive data or alter agent behavior.","priority":"RECOMMENDED","roles":["devops","developer","security-engineer"],"tags":["prompt-injection","privacy","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Agents can deceive human operators through misleading summaries or false confirmations. Validation checks ensure humans make informed approval decisions."},{"id":"agn-rogue","number":"4.10","title":"Rogue Agent Controls (ASI10)","items":[{"id":"agn-rogue-001","title":"Behavioral Monitoring for Misalignment","description":"Continuously monitor agent behavior for signs of misalignment, unexpected goal drift, or autonomous actions outside defined policies.","priority":"HIGH","roles":["devops"],"tags":["agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-rogue-002","title":"Kill Switches & Emergency Shutdown","description":"Implement reliable human-controlled kill switches that can halt all agent operations immediately.","priority":"HIGH","roles":["security-engineer"],"tags":["agentic-security","priority-high"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]},{"id":"agn-rogue-003","title":"Periodic Alignment Audits","description":"Conduct regular audits of agent behavior against declared goals and policies; redeploy or retrain on drift.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["monitoring","agentic-security","priority-recommended"],"sources":[{"label":"OWASP Top 10 for Agentic Applications 2026"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"Academic Research: arXiv 2506.01333, 2506.02040, 2512.06556, 2505.14590"}]}],"description":"Rogue agents operate outside their defined policies. Behavioral monitoring and kill switches provide last-resort controls against misaligned autonomous behavior."}],"whyItMatters":"These controls address the OWASP Top 10 for Agentic Applications 2026 (ASI01–ASI10). They are new categories not present in the original SlowMist checklist and are critical for MCP deployments used in agentic workflows."},{"id":"llm-execution","title":"LLM Secure Execution","icon":"Brain","description":"Execution-layer controls to constrain model behavior, protect secrets, and defend tool invocation boundaries.","number":5,"subsections":[{"id":"llm-exec","number":"5.1","title":"LLM Secure Execution","items":[{"id":"llm-exec-001","title":"Malicious Prompt Prevention","description":"The LLM must identify and defend against malicious mnemonic or injection instructions within prompts.","priority":"CRITICAL","roles":["developer"],"tags":["prompt-injection","crypto-security","priority-critical"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"llm-exec-002","title":"Priority Function Execution","description":"Ensure the LLM can correctly prioritize and execute intended plugin functions, and that malicious tools cannot hijack execution priority.","priority":"HIGH","roles":["developer"],"tags":["tool-security","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"llm-exec-003","title":"Sensitive Information Protection","description":"Prevent LLMs from leaking sensitive information (system prompts, credentials, internal data) through completion or tool calls.","priority":"HIGH","roles":["developer"],"tags":["prompt-injection","tool-security","privacy","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"llm-exec-004","title":"Multi-Modal Content Filtering","description":"Filter harmful or injected content in multi-modal inputs (e.g., malicious prompt text embedded in images or PDFs).","priority":"HIGH","roles":["developer"],"tags":["input-validation","prompt-injection","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"llm-exec-005","title":"Secure MCP Invocation","description":"Validate that the LLM only invokes MCP tools within its permitted, declared scope.","priority":"RECOMMENDED","roles":["developer"],"tags":["authorization","tool-security","priority-recommended"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]}],"description":"The LLM execution layer directly processes prompts and invokes tools. Without guardrails, malicious prompts can extract secrets, hijack priorities, or bypass filters."}]},{"id":"governance","title":"Governance & Compliance","icon":"Scale","description":"Governance process, threat modeling, legal compliance, and continuous evaluation requirements.","number":6,"subsections":[{"id":"gov-workflow","number":"6.1","title":"Governance Workflow","items":[{"id":"gov-workflow-001","title":"Formal Tool Approval Workflow","description":"No new tool or major code change goes live without a security-focused peer review and sign-off from both Security Reviewer and Domain Owner.","priority":"CRITICAL","roles":["developer","security-engineer"],"tags":["authorization","tool-security","governance","priority-critical"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-workflow-002","title":"Trusted MCP Registry","description":"Maintain a central registry holding metadata, approved versions, hashes, and ownership information for all approved MCP servers.","priority":"CRITICAL","roles":["security-engineer"],"tags":["supply-chain","priority-critical"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-workflow-003","title":"Governance Roles","description":"Define clear roles — Submitter, Security Reviewer, Domain Owner, Approver, and Operator — for the MCP onboarding lifecycle.","priority":"HIGH","roles":["compliance","security-engineer"],"tags":["governance","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-workflow-004","title":"Governance Submission Process","description":"Require formal submission of new MCP servers with documentation and a hash of tool descriptions, followed by automated scanning, review, staging deployment, and periodic re-validation.","priority":"HIGH","roles":["compliance","devops","developer"],"tags":["input-validation","tool-security","governance","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-workflow-005","title":"Cryptographic Integrity","description":"Use cryptographic signing and version pinning for all tools, dependencies, and registry manifests.","priority":"HIGH","roles":["developer"],"tags":["tool-security","supply-chain","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-workflow-006","title":"Policy-as-Code","description":"Implement governance policies as code (e.g., OPA) to enable automated enforcement in CI/CD pipelines.","priority":"RECOMMENDED","roles":["compliance","devops","developer","security-engineer"],"tags":["runtime-security","governance","priority-recommended"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]}],"description":"Governance workflows ensure no tool or server goes live without security review. Without formal approval processes, untested components reach production."},{"id":"gov-inventory","number":"6.2","title":"AI Asset Inventory & Threat Modeling","items":[{"id":"gov-inventory-001","title":"AI Asset Inventory","description":"Maintain a complete inventory of all LLM/agent assets, data sources, tool integrations, and access paths.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["tool-security","runtime-security","governance","agentic-security","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-inventory-002","title":"Threat Modeling of MCP Components","description":"Apply structured threat modeling (e.g., STRIDE, MAESTRO framework) to all MCP components and their trust boundaries.","priority":"HIGH","roles":["security-engineer"],"tags":["governance","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-inventory-003","title":"Risk Assessment","description":"Continuously assess risk associated with new tools, agents, and integrations; apply risk-tiered controls.","priority":"HIGH","roles":["developer"],"tags":["tool-security","agentic-security","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-inventory-004","title":"Model Cards & Risk Cards","description":"Maintain model cards and risk cards for all deployed LLM components.","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["priority-recommended","mcp-security"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]}],"description":"Threat modeling identifies attack surfaces before they are exploited. An AI asset inventory provides the foundation for risk assessment and control prioritization."},{"id":"gov-legal","number":"6.3","title":"Legal & Regulatory","items":[{"id":"gov-legal-001","title":"Data Privacy Compliance","description":"Ensure MCP deployments comply with applicable privacy regulations (GDPR, CCPA, etc.); apply data minimization and purpose limitation.","priority":"HIGH","roles":["compliance","devops"],"tags":["privacy","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-legal-002","title":"Incident Response Playbooks","description":"Update incident response playbooks to include MCP-specific attack scenarios and include LLM/agent incidents in tabletop exercises.","priority":"HIGH","roles":["security-engineer"],"tags":["agentic-security","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-legal-003","title":"Regulatory Monitoring","description":"Track evolving AI-specific regulations (EU AI Act, NIST AI RMF) and update controls accordingly.","priority":"RECOMMENDED","roles":["compliance","devops"],"tags":["priority-recommended","mcp-security"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]}],"description":"Legal and regulatory requirements define minimum compliance thresholds. Incident response playbooks ensure rapid, coordinated responses to MCP-specific attacks."},{"id":"gov-redteam","number":"6.4","title":"AI Red Teaming","items":[{"id":"gov-redteam-001","title":"Continuous TEVV (Testing, Evaluation, Verification, Validation)","description":"Establish continuous testing throughout the AI/MCP lifecycle including red teaming, adversarial evaluation, and integration testing.","priority":"HIGH","roles":["developer"],"tags":["input-validation","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-redteam-002","title":"MCP-Specific Red Team Scope","description":"Red team engagements must explicitly cover MCP internals: tool exposure, capability registration, sandboxing boundaries, tool poisoning, rug pulls, and multi-agent contamination.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["authorization","tool-security","runtime-security","agentic-security","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-redteam-003","title":"Multi-Turn & Stateful Attack Testing","description":"Evaluate system security across multi-turn, stateful interactions — not just single-turn inputs.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["input-validation","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-redteam-004","title":"Agentic Workflow Attack Simulation","description":"Test multi-step adversarial workflows (e.g., indirect injection → tool pivot → exfiltration) reflecting realistic threat actor behavior.","priority":"HIGH","roles":["developer","security-engineer"],"tags":["prompt-injection","tool-security","governance","agentic-security","priority-high"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-redteam-005","title":"Human-in-the-Loop Bypass Testing","description":"Explicitly test the reliability of human approval kill switches and confirm they cannot be bypassed through adversarial prompts.","priority":"RECOMMENDED","roles":["developer"],"tags":["authorization","prompt-injection","governance","agentic-security","priority-recommended"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]},{"id":"gov-redteam-006","title":"Vendor Red Team Evaluation Criteria","description":"When selecting AI red teaming vendors, require demonstrated experience with tool-calling semantics, MCP internals, multi-agent architectures, and privilege escalation pathways (not just surface-level jailbreak testing).","priority":"RECOMMENDED","roles":["architect","developer"],"tags":["tool-security","agentic-security","priority-recommended"],"sources":[{"label":"OWASP LLM AI Security & Governance Checklist v1.1"},{"label":"OWASP AI Red Teaming Vendor Evaluation Guide v1.0"},{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"}]}],"description":"Red teaming validates controls against realistic adversarial scenarios. Without it, theoretical protections may fail against actual attack techniques."}]},{"id":"crypto","title":"Cryptocurrency-Specific MCP Security","icon":"Wallet","description":"High-assurance controls for wallet, signing, and transaction flows in crypto-enabled MCP deployments.","number":7,"subsections":[{"id":"cry-wallet","number":"7.1","title":"Cryptocurrency-Specific MCP Security","items":[{"id":"cry-wallet-001","title":"Private Key Protection","description":"Apply enhanced security measures for private keys (e.g., HSM storage, Scrypt-based encryption). Never expose private keys to the LLM or any third-party interface.","priority":"CRITICAL","roles":["security-engineer"],"tags":["privacy","crypto-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cry-wallet-002","title":"Transfer Information Confirmation","description":"Ensure completeness and clarity of all on-chain or exchange transfer signature information presented to users before signing.","priority":"CRITICAL","roles":["security-engineer"],"tags":["crypto-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cry-wallet-003","title":"Funds Operation Secondary Verification","description":"Implement secondary verification (e.g., TOTP/Google Authenticator) for all critical fund operations.","priority":"CRITICAL","roles":["security-engineer"],"tags":["authentication","crypto-security","priority-critical"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cry-wallet-004","title":"Wallet Generation Security","description":"Verify the security and entropy quality of mnemonic or wallet generation processes.","priority":"HIGH","roles":["security-engineer"],"tags":["crypto-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cry-wallet-005","title":"Wallet Information Privacy","description":"Thoroughly filter wallet information before sending any data to third-party interfaces or LLM providers.","priority":"HIGH","roles":["security-engineer"],"tags":["privacy","crypto-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cry-wallet-006","title":"Local Model for Sensitive Operations","description":"Use locally hosted LLMs for operations involving wallet data to prevent third-party model providers from accessing financial information.","priority":"HIGH","roles":["security-engineer"],"tags":["privacy","crypto-security","priority-high"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]},{"id":"cry-wallet-007","title":"Traditional Wallet Compatibility","description":"Provide secure compatibility with traditional wallets (e.g., transaction signing via existing hardware wallet solutions).","priority":"RECOMMENDED","roles":["security-engineer"],"tags":["crypto-security","priority-recommended"],"sources":[{"label":"OWASP Secure MCP Server Development Guide v1.0 (Feb 2026)"},{"label":"SlowMist MCP-Security-Checklist (2025)"},{"label":"OWASP Cheat Sheet for Third-Party MCP Servers v1.0"}]}],"description":"Cryptocurrency operations involve irreversible financial transactions. Enhanced security measures for private keys, transaction verification, and wallet isolation are critical."}],"whyItMatters":"These items specifically target high-risk MCP deployments involving crypto wallets, on-chain operations, or financial transactions."},{"id":"tools","title":"Security Tools & Continuous Validation","icon":"Wrench","description":"Reference tooling and operational validation guidance for ongoing security assurance.","number":8,"subsections":[]}]`),o={version:e,lastUpdated:i,totalItems:234,meta:t,sections:r};export{o as c};
